/* Suggested markup: <div class="uiwiki-breathing-bracket-loader" tabindex="0"><span>Breathing Bracket Loader</span></div> */
.uiwiki-breathing-bracket-loader {
  display: grid;
  place-items: center;
  min-height: 11rem;
  padding: 1.25rem;
  border: 1px solid #ececee;
  border-radius: 22px;
  background: #ffffff;
  color: #111111;
  font: 700 1rem/1.2 Inter, system-ui, sans-serif;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.04);
  transition: transform 240ms cubic-bezier(.22, 1, .36, 1), box-shadow 240ms ease;
}
.uiwiki-breathing-bracket-loader > span {
  padding: .75rem 1rem;
  border-radius: 999px;
  background: #ff9950;
  animation: breathing_bracket_loader 1.8s ease-in-out infinite alternate;
}
.uiwiki-breathing-bracket-loader:hover,
.uiwiki-breathing-bracket-loader:focus-visible {
  transform: translateY(-3px);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
}
@keyframes breathing_bracket_loader {
  from { transform: translateY(0) scale(1); }
  to { transform: translateY(-4px) scale(1.025); }
}
@media (prefers-reduced-motion: reduce) {
  .uiwiki-breathing-bracket-loader, .uiwiki-breathing-bracket-loader > span { animation: none; transition: none; }
}
